from urllib.parse import urlparse
import ipaddress

def is_safe_url(url: str) -> bool:
    parsed = urlparse(url)
    if parsed.scheme not in ('https', 'http'):
        return False
    try:
        ip = ipaddress.ip_address(parsed.hostname)
        if ip.is_private or ip.is_loopback or ip.is_link_local:
            return False
    except ValueError:
        pass  # hostname, not IP
    return True

from starlette.middleware.base import BaseHTTPMiddleware
from starlette.responses import RedirectResponse

class HTTPSRedirectMiddleware:
    async def __call__(self, request, call_next):
        if request.url.scheme != 'https' and not request.url.hostname.startswith('localhost'):
            url = request.url.replace(scheme='https')
            return RedirectResponse(url)
        return await call_next(request)

import uuid
import os
from pathlib import Path

ALLOWED_EXTENSIONS = {'.jpg', '.png', '.gif', '.pdf'}
MAX_SIZE = 5 * 1024 * 1024  # 5MB

def save_upload(upload_file) -> str:
    ext = Path(upload_file.filename).suffix.lower()
    if ext not in ALLOWED_EXTENSIONS:
        raise ValueError(f'Extension {ext} not allowed')
    if upload_file.content_type not in ['image/jpeg', 'image/png', 'application/pdf']:
        raise ValueError('Invalid MIME type')
    filename = f'{uuid.uuid4()}{ext}'
    filepath = Path('uploads') / filename
    with open(filepath, 'wb') as f:
        f.write(upload_file.file.read())
    return str(filepath)

from pathlib import Path

def safe_read(base_dir: str, filename: str) -> bytes:
    base = Path(base_dir).resolve()
    filepath = (base / filename).resolve()
    # Ensure filepath is within base_dir
    if not str(filepath).startswith(str(base)):
        raise PermissionError('Access denied')
    if not filepath.exists():
        raise FileNotFoundError('File not found')
    return filepath.read_bytes()
